import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

// Behavior under test (see src/parseQuery.js header comment):
//   - qs may have a leading "?"
//   - pairs separated by "&"; empty segments are skipped
//   - single key -> string value; repeated key -> array in order
//   - bare key (no "=") -> ""
//   - "+" -> space in keys and values, then percent-decode
//   - decode failure -> raw token (after "+" replacement), never throws

describe("parseQuery", () => {
  describe("empty and trivial inputs", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns an empty object for a lone '?'", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("returns an empty object when the string is only separators", () => {
      expect(parseQuery("&&&")).toEqual({});
    });

    it("returns an empty object for '?' followed only by separators", () => {
      expect(parseQuery("?&&")).toEqual({});
    });

    it("always returns a fresh plain object", () => {
      const a = parseQuery("x=1");
      const b = parseQuery("x=1");
      expect(a).not.toBe(b);
      expect(Object.getPrototypeOf(a)).toBe(Object.prototype);
    });
  });

  describe("leading '?' handling", () => {
    it("ignores a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses identically with and without the leading '?'", () => {
      expect(parseQuery("?a=1&b=2")).toEqual(parseQuery("a=1&b=2"));
    });

    it("strips only the first '?', leaving a second one in the key", () => {
      // Only the leading "?" is removed; the remaining "?" is part of the key.
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("treats a non-leading '?' as an ordinary character", () => {
      expect(parseQuery("a=1?b=2")).toEqual({ a: "1?b=2" });
    });
  });

  describe("single key/value pairs", () => {
    it("maps a key to its string value", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("keeps values as strings, not numbers", () => {
      const result = parseQuery("n=42");
      expect(result.n).toBe("42");
      expect(typeof result.n).toBe("string");
    });

    it("handles multiple distinct keys", () => {
      expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
    });

    it("maps a key with an empty value ('a=') to an empty string", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });

    it("allows an empty key ('=1')", () => {
      expect(parseQuery("=1")).toEqual({ "": "1" });
    });

    it("allows a bare '=' as empty key mapped to empty value", () => {
      expect(parseQuery("=")).toEqual({ "": "" });
    });

    it("splits only on the first '=', keeping later '='s in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("preserves multiple '='s in the value verbatim", () => {
      expect(parseQuery("eq====")).toEqual({ eq: "===" });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("handles multiple bare keys", () => {
      expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
    });

    it("mixes bare keys and key/value pairs", () => {
      expect(parseQuery("a&b=2&c")).toEqual({ a: "", b: "2", c: "" });
    });
  });

  describe("empty segments", () => {
    it("skips empty segments between pairs", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips a leading empty segment", () => {
      expect(parseQuery("&a=1")).toEqual({ a: "1" });
    });

    it("skips a trailing empty segment", () => {
      expect(parseQuery("a=1&")).toEqual({ a: "1" });
    });

    it("skips runs of consecutive separators", () => {
      expect(parseQuery("a=1&&&&b=2")).toEqual({ a: "1", b: "2" });
    });
  });

  describe("repeated keys", () => {
    it("collects two occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("collects three or more occurrences into an array in order", () => {
      expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
    });

    it("preserves order of appearance even when interleaved with other keys", () => {
      expect(parseQuery("a=1&b=x&a=2&b=y&a=3")).toEqual({
        a: ["1", "2", "3"],
        b: ["x", "y"],
      });
    });

    it("uses an array (not a string) once a key repeats", () => {
      const result = parseQuery("a=1&a=2");
      expect(Array.isArray(result.a)).toBe(true);
    });

    it("does not use an array for a key that appears only once", () => {
      const result = parseQuery("a=1&b=2");
      expect(Array.isArray(result.a)).toBe(false);
      expect(result.a).toBe("1");
    });

    it("collects repeated empty values", () => {
      expect(parseQuery("a=&a=")).toEqual({ a: ["", ""] });
    });

    it("collects repeated bare keys as empty strings", () => {
      expect(parseQuery("flag&flag")).toEqual({ flag: ["", ""] });
    });

    it("groups keys that repeat after being seen once via a bare key", () => {
      expect(parseQuery("a&a=2")).toEqual({ a: ["", "2"] });
    });
  });

  describe("'+' decodes to space", () => {
    it("replaces '+' with a space in values", () => {
      expect(parseQuery("a=b+c")).toEqual({ a: "b c" });
    });

    it("replaces '+' with a space in keys", () => {
      expect(parseQuery("a+b=c")).toEqual({ "a b": "c" });
    });

    it("replaces every '+' in a token", () => {
      expect(parseQuery("a=1+2+3")).toEqual({ a: "1 2 3" });
    });
  });

  describe("percent-decoding", () => {
    it("percent-decodes values", () => {
      expect(parseQuery("a=%2Fpath")).toEqual({ a: "/path" });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("a%20b=c")).toEqual({ "a b": "c" });
    });

    it("decodes multi-byte UTF-8 percent sequences", () => {
      expect(parseQuery("emoji=%F0%9F%98%80")).toEqual({ emoji: "\u{1F600}" });
    });

    it("decodes an encoded '&' inside a value without splitting on it", () => {
      expect(parseQuery("a=x%26y")).toEqual({ a: "x&y" });
    });

    it("decodes an encoded '=' inside a value", () => {
      expect(parseQuery("a=x%3Dy")).toEqual({ a: "x=y" });
    });

    it("applies '+' replacement before percent-decoding", () => {
      // "%2B" is an encoded '+' and must survive as a literal '+',
      // while a literal '+' becomes a space.
      expect(parseQuery("a=%2B")).toEqual({ a: "+" });
      expect(parseQuery("a=+")).toEqual({ a: " " });
    });

    it("handles a token mixing encoded spaces and literal '+'", () => {
      expect(parseQuery("a=%20+")).toEqual({ a: "  " });
    });
  });

  describe("malformed percent-encoding never throws", () => {
    it("returns a lone '%' unchanged rather than throwing", () => {
      expect(() => parseQuery("a=%")).not.toThrow();
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("returns an invalid escape ('%zz') unchanged", () => {
      expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
    });

    it("returns a truncated escape ('%2') unchanged", () => {
      expect(parseQuery("a=%2")).toEqual({ a: "%2" });
    });

    it("falls back for an invalid escape in the key", () => {
      expect(parseQuery("%=1")).toEqual({ "%": "1" });
    });

    it("still applies '+' replacement on the fallback token", () => {
      // Decoding "a %" fails, so the raw token AFTER "+" replacement is used.
      expect(parseQuery("a+%=b")).toEqual({ "a %": "b" });
    });

    it("does not throw on any malformed input in a mixed string", () => {
      expect(() => parseQuery("ok=1&bad=%&flag&x=%GG")).not.toThrow();
      expect(parseQuery("ok=1&bad=%&flag&x=%GG")).toEqual({
        ok: "1",
        bad: "%",
        flag: "",
        x: "%GG",
      });
    });
  });

  describe("realistic combinations", () => {
    it("parses a representative query string", () => {
      expect(
        parseQuery("?name=John+Doe&role=admin&role=editor&active&note=a%3Db"),
      ).toEqual({
        name: "John Doe",
        role: ["admin", "editor"],
        active: "",
        note: "a=b",
      });
    });
  });
});

